import{_ as a,c as i,o as d,a1 as e}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"플랫폼 및 통합: macOS, Windows, Linux 터미널 기능 및 지원 상세 설명 | opencode-notify","description":"macOS, Windows, Linux에서의 opencode-notify 기능 차이를 학습하고, 터미널 지원(37+ 터미널 에뮬레이터), 포커스 감지, 클릭 포커스 및 사용자 정의 사운드 등 플랫폼 특성을 마스터하세요. 이 장에서는 플랫폼 기능 비교, 터미널 감지 메커니즘 및 설정 가이드를 포함하여 운영 체제와 터미널 유형에 따라 알림 경험을 최적화하고 업무 효율성을 높이는 데 도움을 드립니다.","frontmatter":{"title":"플랫폼 및 통합: macOS, Windows, Linux 터미널 기능 및 지원 상세 설명 | opencode-notify","sidebarTitle":"플랫폼에 맞추기","subtitle":"플랫폼 및 통합","description":"macOS, Windows, Linux에서의 opencode-notify 기능 차이를 학습하고, 터미널 지원(37+ 터미널 에뮬레이터), 포커스 감지, 클릭 포커스 및 사용자 정의 사운드 등 플랫폼 특성을 마스터하세요. 이 장에서는 플랫폼 기능 비교, 터미널 감지 메커니즘 및 설정 가이드를 포함하여 운영 체제와 터미널 유형에 따라 알림 경험을 최적화하고 업무 효율성을 높이는 데 도움을 드립니다.","tags":["플랫폼 기능","터미널 지원","시스템 호환성"],"prerequisite":["start-quick-start","start-how-it-works"],"order":2},"headers":[],"relativePath":"ko/kdcokenny/opencode-notify/platforms/index.md","filePath":"ko/kdcokenny/opencode-notify/platforms/index.md"}'),o={name:"ko/kdcokenny/opencode-notify/platforms/index.md"};function l(r,t,n,s,h,c){return d(),i("div",null,[...t[0]||(t[0]=[e('<h1 id="플랫폼-및-통합" tabindex="-1">플랫폼 및 통합 <a class="header-anchor" href="#플랫폼-및-통합" aria-label="Permalink to &quot;플랫폼 및 통합&quot;">​</a></h1><p>이 장에서는 opencode-notify가 다른 운영 체제에서 어떻게 작동하는지 이해하고, 플랫폼별 설정을 마스터하며, 터미널의 최고 성능을 발휘하도록 돕습니다.</p><h2 id="학습-경로" tabindex="-1">학습 경로 <a class="header-anchor" href="#학습-경로" aria-label="Permalink to &quot;학습 경로&quot;">​</a></h2><h3 id="_1-macos-플랫폼-기능" tabindex="-1">1. <a href="./../macos/">macOS 플랫폼 기능</a> <a class="header-anchor" href="#_1-macos-플랫폼-기능" aria-label="Permalink to &quot;1. [macOS 플랫폼 기능](../macos/)&quot;">​</a></h3><p>macOS의 고급 기능을 완전히 이해하고 스마트 포커스 감지, 클릭 알림 포커스, 사용자 정의 사운드를 사용하세요.</p><ul><li>포커스 감지: 터미널이 현재 활성 창인지 자동 판단</li><li>클릭 포커스: 알림 클릭 시 자동으로 터미널로 전환</li><li>사용자 정의 사운드: 다양한 이벤트에 전용 사운드 설정</li><li>37+ 터미널 지원: Ghostty, iTerm2, VS Code 통합 터미널 등 포함</li></ul><h3 id="_2-windows-플랫폼-기능" tabindex="-1">2. <a href="./../windows/">Windows 플랫폼 기능</a> <a class="header-anchor" href="#_2-windows-플랫폼-기능" aria-label="Permalink to &quot;2. [Windows 플랫폼 기능](../windows/)&quot;">​</a></h3><p>Windows 플랫폼의 알림 기초와 설정 방법을 마스터하세요.</p><ul><li>기본 알림: Windows 10/11 알림 센터 사용</li><li>알림 권한: OpenCode가 알림을 보낼 권한이 있는지 확인</li><li>기본 설정: Windows 환경에서의 설정 파일 위치</li><li>제한 사항: Windows는 현재 포커스 감지 기능을 지원하지 않음</li></ul><h3 id="_3-linux-플랫폼-기능" tabindex="-1">3. <a href="./../linux/">Linux 플랫폼 기능</a> <a class="header-anchor" href="#_3-linux-플랫폼-기능" aria-label="Permalink to &quot;3. [Linux 플랫폼 기능](../linux/)&quot;">​</a></h3><p>Linux 플랫폼의 알림 메커니즘과 종속성 설치를 이해하세요.</p><ul><li>libnotify 통합: notify-send를 사용하여 알림 전송</li><li>데스크톱 환경 지원: GNOME, KDE Plasma, XFCE 등 주요 환경</li><li>종속성 설치: 다른 배포판용 설치 명령어</li><li>제한 사항: Linux는 현재 포커스 감지 기능을 지원하지 않음</li></ul><h3 id="_4-지원되는-터미널" tabindex="-1">4. <a href="./../terminals/">지원되는 터미널</a> <a class="header-anchor" href="#_4-지원되는-터미널" aria-label="Permalink to &quot;4. [지원되는 터미널](../terminals/)&quot;">​</a></h3><p>모든 37+ 지원되는 터미널 에뮬레이터를 보고 자동 감지 메커니즘을 이해하세요.</p><ul><li>터미널 감지: 터미널 유형을 자동으로 식별하는 방법</li><li>터미널 목록: 완전한 지원 터미널 목록</li><li>수동 설정: 자동 감지가 실패할 때 수동으로 지정하는 방법</li><li>특수 터미널: VS Code 통합 터미널, 원격 SSH 세션 처리</li></ul><h2 id="사전-요구사항" tabindex="-1">사전 요구사항 <a class="header-anchor" href="#사전-요구사항" aria-label="Permalink to &quot;사전 요구사항&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">이 장을 학습하기 전에 다음을 완료했는지 확인하세요</p><ul><li>✅ <strong><a href="./../../start/quick-start/">빠른 시작</a></strong>: opencode-notify 설치 완료</li><li>✅ <strong><a href="./../../start/how-it-works/">작동 원리</a></strong>: 4가지 알림 유형과 스마트 필터링 메커니즘 이해</li></ul></div><h2 id="플랫폼-선택-권장사항" tabindex="-1">플랫폼 선택 권장사항 <a class="header-anchor" href="#플랫폼-선택-권장사항" aria-label="Permalink to &quot;플랫폼 선택 권장사항&quot;">​</a></h2><p>운영 체제에 따라 해당 장을 선택하세요:</p><table tabindex="0"><thead><tr><th>운영 체제</th><th>권장 학습 순서</th><th>핵심 기능</th></tr></thead><tbody><tr><td><strong>macOS</strong></td><td>1. macOS 플랫폼 기능 → 4. 지원되는 터미널</td><td>포커스 감지, 클릭 포커스, 사용자 정의 사운드</td></tr><tr><td><strong>Windows</strong></td><td>2. Windows 플랫폼 기능 → 4. 지원되는 터미널</td><td>기본 알림, 기본 설정</td></tr><tr><td><strong>Linux</strong></td><td>3. Linux 플랫폼 기능 → 4. 지원되는 터미널</td><td>libnotify 통합, 종속성 설치</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">일반적인 권장사항</p><p>어떤 플랫폼을 사용하든, 4과목「지원되는 터미널」을 학습할 가치가 있습니다. 이를 통해 터미널 감지 메커니즘을 이해하고 설정 문제를 해결할 수 있습니다.</p></div><h2 id="기능-비교표" tabindex="-1">기능 비교표 <a class="header-anchor" href="#기능-비교표" aria-label="Permalink to &quot;기능 비교표&quot;">​</a></h2><table tabindex="0"><thead><tr><th>기능</th><th>macOS</th><th>Windows</th><th>Linux</th></tr></thead><tbody><tr><td>기본 알림</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>터미널 포커스 감지</td><td>✅</td><td>❌</td><td>❌</td></tr><tr><td>알림 클릭 포커스</td><td>✅</td><td>❌</td><td>❌</td></tr><tr><td>사용자 정의 사운드</td><td>✅</td><td>✅</td><td>✅ (부분적)</td></tr><tr><td>무음 시간</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>상위 세션 확인</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>37+ 터미널 지원</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>자동 터미널 감지</td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table><h2 id="다음-단계" tabindex="-1">다음 단계 <a class="header-anchor" href="#다음-단계" aria-label="Permalink to &quot;다음 단계&quot;">​</a></h2><p>이 장을 완료하면 다른 플랫폼의 기능 차이와 설정 방법을 이해하게 됩니다.</p><p>계속 학습하는 것을 권장합니다:</p><h3 id="고급-설정" tabindex="-1"><a href="./../../advanced/config-reference/">고급 설정</a> <a class="header-anchor" href="#고급-설정" aria-label="Permalink to &quot;[고급 설정](../../advanced/config-reference/)&quot;">​</a></h3><p>설정 파일의 모든 옵션을 심층적으로 학습하고 고급 설정 기술을 마스터하세요.</p><ul><li>완전한 설정 참조: 모든 설정 항목의 자세한 설명</li><li>무음 시간 상세 설명: 설정 방법과 작동 원리</li><li>터미널 감지 원리: 자동 감지의 내부 메커니즘</li><li>고급 사용법: 설정 기술과 모범 사례</li></ul><h3 id="문제-해결" tabindex="-1"><a href="./../../faq/troubleshooting/">문제 해결</a> <a class="header-anchor" href="#문제-해결" aria-label="Permalink to &quot;[문제 해결](../../faq/troubleshooting/)&quot;">​</a></h3><p>문제가 발생할 때 일반적인 문제의 해결 방법을 확인하세요.</p><ul><li>알림이 표시되지 않음: 권한 및 시스템 설정 문제</li><li>포커스 감지 실패: 터미널 설정 및 감지 메커니즘</li><li>설정 오류: 설정 파일 형식 및 필드 설명</li><li>사운드 문제: 사운드 설정 및 시스템 호환성</li></ul><div class="info custom-block"><p class="custom-block-title">학습 경로 권장사항</p><p>처음 사용하는 경우 <strong>플랫폼 장 → 고급 설정 → 문제 해결</strong> 순서로 학습하는 것을 권장합니다. 구체적인 문제가 발생하면 문제 해결 장으로 바로 이동할 수 있습니다.</p></div>',33)])])}const f=a(o,[["render",l]]);export{p as __pageData,f as default};
